Explain what this TypeScript function does, how it works, and when you would use it:

```typescript
function* paginate<T>(items: T[], pageSize: number): Generator<T[]> {
  for (let i = 0; i < items.length; i += pageSize) {
    yield items.slice(i, i + pageSize);
  }
}

// Usage
const pages = paginate([1, 2, 3, 4, 5, 6, 7], 3);
for (const page of pages) {
  console.log(page);
}
```

